import{p as n,bh as i,I as a,U as h}from"./chunks/framework.BpabEsSf.js";const g=JSON.parse('{"title":"Khởi động nhanh","description":"","frontmatter":{"title":"Khởi động nhanh","date":"2025-05-01T23:00:00.000Z","permalink":"/guide/quickstart","categories":["Guide"],"tags":["Guide"],"top":true,"sticky":1},"headers":[],"relativePath":"vi/01.Guide/01.Introduction/10.Quick Start.md","filePath":"vi/01.Guide/01.Introduction/10.Quick Start.md","lastUpdated":null}'),e={name:"vi/01.Guide/01.Introduction/10.Quick Start.md"};function o(r,t,c,d,l,s){return i(),a("div",null,[...t[0]||(t[0]=[h('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /vi\\01.Guide\\01.Introduction\\10.Quick Start.md for this page in Markdown format</div><h1 id="khoi-đong-nhanh" tabindex="-1">Khởi động nhanh <a class="header-anchor" href="#khoi-đong-nhanh" aria-label="Permalink to &quot;Khởi động nhanh&quot;">​</a></h1><h3 id="cai-đat-nhanh" tabindex="-1">Cài đặt nhanh <a class="header-anchor" href="#cai-đat-nhanh" aria-label="Permalink to &quot;Cài đặt nhanh&quot;">​</a></h3><h4 id="android" tabindex="-1">Android: <a class="header-anchor" href="#android" aria-label="Permalink to &quot;Android:&quot;">​</a></h4><ol><li>Tải xuống gói APK mới nhất từ trang phát hành chính thức <strong><a href="https://github.com/JoyinJoester/Monica/releases" target="_blank" rel="noreferrer">Releases</a></strong>.</li><li>Cài đặt gói ứng dụng trên bất kỳ thiết bị nào chạy <strong>Android 8.0+</strong> và thiết lập Mật khẩu chủ của bạn trong lần khởi chạy đầu tiên.</li></ol><h4 id="tien-ich-mo-rong-trinh-duyet-chrome-edge" tabindex="-1">Tiện ích mở rộng trình duyệt (Chrome / Edge): <a class="header-anchor" href="#tien-ich-mo-rong-trinh-duyet-chrome-edge" aria-label="Permalink to &quot;Tiện ích mở rộng trình duyệt (Chrome / Edge):&quot;">​</a></h4><ol><li>Di chuyển đến thư mục dự án cục bộ <code>Monica for Browser</code> để xây dựng (build) các tài nguyên của tiện ích mở rộng.</li><li>Mở trang <code>chrome://extensions/</code> trong trình duyệt của bạn và kích hoạt <strong>&quot;Chế độ dành cho nhà phát triển&quot;</strong> ở góc trên cùng bên phải.</li><li>Nhấp vào nút <strong>&quot;Tải tiện ích đã giải nén&quot;</strong> và chọn thư mục phân phối <code>dist</code> vừa được tạo ra.</li></ol><hr><h3 id="han-che-đa-biet" tabindex="-1">Hạn chế đã biết <a class="header-anchor" href="#han-che-đa-biet" aria-label="Permalink to &quot;Hạn chế đã biết&quot;">​</a></h3><ul><li>Do sự khác biệt về cấu hình và hạn chế khả năng tương thích ở cấp độ hệ thống, Monica for Android hiện tại không thể khởi tạo hoặc tạo mã khóa <strong>Passkey</strong> trên một số thiết bị chạy hệ điều hành <strong>Xiaomi HyperOS</strong>.</li></ul>',10)])])}const m=n(e,[["render",o]]);export{g as __pageData,m as default};
